from dataclasses import dataclass
from enum import Enum
from typing import Optional
import datetime


class DeprecatedVersionState(Enum):
    SUPPORTED     = "supported"      # Full support; no warnings
    DEPRECATED    = "deprecated"     # Sunset notice published; still fully functional
    WARNING       = "warning"        # Within 60 days of sunset; headers added
    SUNSET        = "sunset"         # Past sunset date; in grace period
    GRACE_LIMITED = "grace_limited"  # In grace period with limited support
    RETIRED       = "retired"        # Hard cutoff; 410 Gone


@dataclass
class DeprecatedVersionLifecycle:
    version_id: str
    announcement_date: str   # ISO-8601
    sunset_date: str         # ISO-8601
    grace_period_days: int
    migration_track: str     # "drop_in" | "prompt_adapt" | "arch_migrate"

    def grace_end_date(self) -> datetime.date:
        sunset = datetime.date.fromisoformat(self.sunset_date)
        return sunset + datetime.timedelta(days=self.grace_period_days)

    def current_state(self) -> DeprecatedVersionState:
        today = datetime.date.today()
        sunset = datetime.date.fromisoformat(self.sunset_date)
        grace_end = self.grace_end_date()

        if today >= grace_end:
            return DeprecatedVersionState.RETIRED
        if today >= sunset:
            return DeprecatedVersionState.GRACE_LIMITED
        if today >= sunset - datetime.timedelta(days=60):
            return DeprecatedVersionState.WARNING
        if today >= datetime.date.fromisoformat(self.announcement_date):
            return DeprecatedVersionState.DEPRECATED
        return DeprecatedVersionState.SUPPORTED

    def days_until_grace_end(self) -> int:
        return (self.grace_end_date() - datetime.date.today()).days

    def support_scope(self) -> str:
        state = self.current_state()
        scopes = {
            DeprecatedVersionState.SUPPORTED:     "Full support: features, bugs, security",
            DeprecatedVersionState.DEPRECATED:    "Full support: features, bugs, security (migration encouraged)",
            DeprecatedVersionState.WARNING:       "Bug fixes and security patches only",
            DeprecatedVersionState.SUNSET:        "Security patches only; no bug fixes",
            DeprecatedVersionState.GRACE_LIMITED: "Security patches only; no bug fixes",
            DeprecatedVersionState.RETIRED:       "No support: 410 Gone",
        }
        return scopes[state]

    def lifecycle_summary(self) -> str:
        state = self.current_state()
        days = self.days_until_grace_end()
        return (
            f"{self.version_id}: {state.value}\n"
            f"  Support: {self.support_scope()}\n"
            f"  Days until hard cutoff: {days if days > 0 else 'RETIRED'}\n"
            f"  Grace end: {self.grace_end_date().isoformat()}"
        )

from dataclasses import dataclass
from enum import Enum
from typing import Optional
import datetime


class PostGraceOutcome(Enum):
    RETIRED_HARD    = "retired_hard"   # 410 Gone; no further accommodation
    EMERGENCY_GRACE = "emergency_grace"  # Short extension for genuine emergency
    REDIRECTED      = "redirected"     # API gateway auto-redirects to replacement


@dataclass
class PostGraceCallerRecord:
    caller_id: str
    team_name: str
    traffic_at_grace_end_pct: float
    reason_still_on_old_version: str
    has_active_exception: bool
    emergency_grace_approved: bool = False
    emergency_grace_end_date: Optional[str] = None  # ISO-8601, max 2 sprints
    outcome: PostGraceOutcome = PostGraceOutcome.RETIRED_HARD

    def is_eligible_for_emergency_grace(self) -> bool:
        """Emergency grace is only for callers with < 1 sprint of work remaining."""
        eligible_reasons = [
            "migration in testing",
            "canary in progress",
            "final validation pending",
        ]
        return any(r in self.reason_still_on_old_version.lower() for r in eligible_reasons)

    def post_grace_summary(self) -> str:
        outcome_label = self.outcome.value
        if self.emergency_grace_approved and self.emergency_grace_end_date:
            outcome_label += f" (emergency grace until {self.emergency_grace_end_date})"
        return (
            f"{self.caller_id} ({self.team_name}): "
            f"{self.traffic_at_grace_end_pct:.1f}% traffic | "
            f"outcome: {outcome_label}"
        )


@dataclass
class PostGracePolicy:
    notice_id: str
    max_emergency_grace_days: int = 14   # Maximum 2 sprints; no exceptions
    allow_auto_redirect: bool = True     # Route callers to replacement silently if semantics match

    def evaluate_caller(self, record: PostGraceCallerRecord) -> PostGraceOutcome:
        if self.allow_auto_redirect and record.traffic_at_grace_end_pct < 1.0:
            # Low-traffic callers on drop-in replacement track: auto-redirect without outage
            return PostGraceOutcome.REDIRECTED
        if record.is_eligible_for_emergency_grace() and not record.has_active_exception:
            return PostGraceOutcome.EMERGENCY_GRACE
        return PostGraceOutcome.RETIRED_HARD
